# =====================================================================
# FUNÇÕES DE RENOMEAÇÃO
# =====================================================================

def renomear_betfair(df):
    """Renomeia DataFrame da Betfair"""
    if df is None: return None
    df = df.copy()
    
    # Renomear ligas
    if LIGAS_BETFAIR:
        df['League'] = df['League'].map(LIGAS_BETFAIR).fillna(df['League'])
    
    # Renomear times
    if TIMES_BETFAIR:
        for liga_padrao, times_map in TIMES_BETFAIR.items():
            mask = df['League'] == liga_padrao
            if mask.any():
                df.loc[mask, 'Home'] = df.loc[mask, 'Home'].map(times_map).fillna(df.loc[mask, 'Home'])
                df.loc[mask, 'Away'] = df.loc[mask, 'Away'].map(times_map).fillna(df.loc[mask, 'Away'])
    
    return df

def renomear_footystats(df):
    """Renomeia DataFrame do FootyStats"""
    if df is None: return None
    df = df.copy()
    
    # Renomear ligas
    if LIGAS_FOOTYSTATS:
        df['League'] = df['League'].map(LIGAS_FOOTYSTATS).fillna(df['League'])
    
    # Renomear times
    if TIMES_FOOTYSTATS:
        for liga_padrao, times_map in TIMES_FOOTYSTATS.items():
            mask = df['League'] == liga_padrao
            if mask.any():
                df.loc[mask, 'Home'] = df.loc[mask, 'Home'].map(times_map).fillna(df.loc[mask, 'Home'])
                df.loc[mask, 'Away'] = df.loc[mask, 'Away'].map(times_map).fillna(df.loc[mask, 'Away'])
    
    return df

def renomear_todas_bases(df_betfair=None, df_footystats=None):
    """Renomeia Betfair e FootyStats para o padrão"""
    return (
        renomear_betfair(df_betfair) if df_betfair is not None else None,
        renomear_footystats(df_footystats) if df_footystats is not None else None
    )

